// inferred-not-tested:传 custom canvas,避免默认写 document.body
import JSConfetti from 'https://cdn.jsdelivr.net/npm/js-confetti@0/+esm';
const host = document.getElementById('confetti'); host.style.cssText = `position:relative;height:${spec.height ?? 240}px;overflow:hidden`;
const canvas = document.createElement('canvas'); canvas.style.cssText = 'position:absolute;inset:0;width:100%;height:100%'; host.appendChild(canvas);
const fx = new JSConfetti({canvas});
await (data.origin ? fx.addConfettiAtPosition({...data.options, confettiDispatchPosition:data.origin}) : fx.addConfetti(data.options ?? {}));

